const items = $input.all();
const agendamentos = items.filter(i => i.json.id_agendamento);

if (agendamentos.length === 0) {
  return [{ json: { resultado: 'Nenhum agendamento futuro encontrado para este paciente.' } }];
}

let resultado = 'Próximos agendamentos:\n';
for (const a of agendamentos) {
  const d = a.json;
  const date = new Date(d.data_consulta).toLocaleDateString('pt-BR');
  resultado += `\n📋 ID: ${d.id_agendamento}\n`;
  resultado += `   📅 ${date} às ${d.hora_consulta.substring(0,5)}\n`;
  resultado += `   👨‍⚕️ Dr(a). ${d.nome_dentista} (${d.especialidade_dentista || 'Clínica Geral'})\n`;
  if (d.nome_procedimento) resultado += `   🦷 ${d.nome_procedimento}\n`;
  resultado += `   Status: ${d.status}\n`;
}

return [{ json: { resultado } }];
